module DAC_24bit (  
    input wire clk,  
    input wire reset,  
    input wire [23:0] digital_input,  
    output reg [23:0] analog_output  
);  

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin  
        if (reset)  
            analog_output <= 24'b0;  
        else  
            analog_output <= digital_input;  
    end  
endmodule
